#include <stdio.h>
#include <stdlib.h>
typedef struct Node {
    int key;
    int value;
    struct Node* prev;
    struct Node* next;
} Node;
typedef struct LRUCache {
    int capacity;
    Node** cache;
    Node* head;
    Node* tail;
} LRUCache;
Node* createNode(int key, int value) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->key = key;
    node->value = value;
    node->prev = NULL;
    node->next = NULL;
    return node;
}
LRUCache* createLRUCache(int capacity) {
    LRUCache* cache = (LRUCache*)malloc(sizeof(LRUCache));
    cache->capacity = capacity;
    cache->cache = (Node**)calloc(capacity, sizeof(Node*));
    cache->head = createNode(0, 0);
    cache->tail = createNode(0, 0);
    cache->head->next = cache->tail;
    cache->tail->prev = cache->head;
    return cache;
}
int getValue(LRUCache* cache, int key) {
    if (cache->cache[key] != NULL) {
        Node* node = cache->cache[key];
        node->prev->next = node->next;
        node->next->prev = node->prev;
        node->next = cache->head->next;
        node->prev = cache->head;
        cache->head->next->prev = node;
        cache->head->next = node;
        return node->value;
    } else {
        return -1;
    }
}
void putValue(LRUCache* cache, int key, int value) {
    if (cache->cache[key] != NULL) {
        cache->cache[key]->value = value;
        Node* node = cache->cache[key];
        node->prev->next = node->next;
        node->next->prev = node->prev;
        node->next = cache->head->next;
        node->prev = cache->head;
        cache->head->next->prev = node;
        cache->head->next = node;
    } else {
        Node* node = createNode(key, value);
        cache->cache[key] = node;
        node->next = cache->head->next;
        node->prev = cache->head;
        cache->head->next->prev = node;
        cache->head->next = node;
        if (cache->capacity == 0) {
            Node* lru = cache->tail->prev;
            cache->cache[lru->key] = NULL;
            lru->prev->next = lru->next;
            lru->next->prev = lru->prev;
            free(lru);
        } else {
            cache->capacity--;
        }
    }
}
int main() {
