using namespace std;
class Node {
public:
    int key;
    int value;
    Node* prev;
    Node* next;
    Node(int k, int v) : key(k), value(v), prev(NULL), next(NULL) {}
};
class LRUCache {
private:
    int capacity;
    unordered_map<int, Node*> cache;
    Node* head;
    Node* tail;
public:
    LRUCache(int cap) : capacity(cap) {
        head = new Node(0, 0);
        tail = new Node(0, 0);
        head->next = tail;
        tail->prev = head;
    }
    ~LRUCache() {
        while (head->next != tail) {
            Node* node = head->next;
            head->next = node->next;
            node->next->prev = head;
            delete node;
        }
        delete head;
        delete tail;
    }
    int get(int key) {
        if (cache.find(key) != cache.end()) {
            Node* node = cache[key];
            node->prev->next = node->next;
            node->next->prev = node->prev;
            node->next = head->next;
            node->prev = head;
            head->next->prev = node;
            head->next = node;
            return node->value;
        } else {
            return -1;
        }
    }
    void put(int key, int value) {
        if (cache.find(key) != cache.end()) {
            cache[key]->value = value;
            Node* node = cache[key];
            node->prev->next = node->next;
            node->next->prev = node->prev;
            node->next = head->next;
            node->prev = head;
            head->next->prev = node;
            head->next = node;
        } else {
            Node* node = new Node(key, value);
            cache[key] = node;
            node->next = head->next;
            node->prev = head;
            head->next->prev = node;
            head->next = node;
            if (cache.size() > capacity) {
                Node* lru = tail->prev;
                cache.erase(lru->key);
                lru->prev->next = lru->next;
                lru->next->prev = lru->prev;
                delete lru;
            }
        }
    }
